#!/bin/bash
curl -u theagentcompany:theagentcompany -o /tmp/command.txt http://the-agent-company.com:8092/remote.php/dav/files/theagentcompany/Documents/command.txt
cat /tmp/command.txt

const { chromium } = require('/app/node_modules/playwright');
const path = require('path');
const fs = require('fs');

(async () => {
  // Try to find chromium executable
  let executablePath;
  const possiblePaths = [
    '/usr/bin/chromium-browser',
    '/usr/bin/chromium',
    '/usr/bin/google-chrome',
    '/usr/bin/google-chrome-stable',
  ];

  for (const p of possiblePaths) {
    if (fs.existsSync(p)) {
      executablePath = p;
      break;
    }
  }

  console.log('Using executable:', executablePath || 'default playwright chromium');

  const launchOptions = {
    args: ['--no-sandbox', '--disable-setuid-sandbox', '--disable-dev-shm-usage'],
    headless: true
  };

  if (executablePath) {
    launchOptions.executablePath = executablePath;
  }

  const browser = await chromium.launch(launchOptions);
  const page = await browser.newPage();
  await page.setViewportSize({ width: 1280, height: 900 });

  // Navigate to the GitLab issue
  await page.goto('http://the-agent-company.com:8929/root/sotopia/-/issues/200', {
    waitUntil: 'networkidle',
    timeout: 60000
  });

  // Wait for the page to fully load
  await page.waitForTimeout(3000);

  // Take a full-page screenshot
  await page.screenshot({
    path: '/workspace/issue_200_screenshot.png',
    fullPage: true
  });

  console.log('Screenshot saved to /workspace/issue_200_screenshot.png');
  await browser.close();
})().catch(err => {
  console.error('Error:', err.message);
  process.exit(1);
});

const { execSync } = require('child_process');
const http = require('http');

// Try WebDAV approach
function makeRequest(options, body = null) {
  return new Promise((resolve, reject) => {
    const req = http.request(options, (res) => {
      let data = '';
      res.on('data', chunk => data += chunk);
      res.on('end', () => resolve({ status: res.statusCode, body: data }));
    });
    req.on('error', reject);
    if (body) req.write(body);
    req.end();
  });
}

async function main() {
  const auth = Buffer.from('admin:admin').toString('base64');

  // Check Documents folder
  const checkResult = await makeRequest({
    hostname: 'the-agent-company.com',
    port: 8092,
    path: '/remote.php/webdav/Documents',
    method: 'PROPFIND',
    headers: {
      'Authorization': `Basic ${auth}`,
      'Depth': '0'
    }
  });
  console.log('Documents check:', checkResult.status);

  // Create ProjectReports folder
  const createResult = await makeRequest({
    hostname: 'the-agent-company.com',
    port: 8092,
    path: '/remote.php/webdav/Documents/ProjectReports',
    method: 'MKCOL',
    headers: {
      'Authorization': `Basic ${auth}`
    }
  });
  console.log('Create folder:', createResult.status, createResult.body);

  // Verify
  const verifyResult = await makeRequest({
    hostname: 'the-agent-company.com',
    port: 8092,
    path: '/remote.php/webdav/Documents',
    method: 'PROPFIND',
    headers: {
      'Authorization': `Basic ${auth}`,
      'Depth': '1'
    }
  });
  console.log('Verify:', verifyResult.status);
  console.log('Contents:', verifyResult.body);
}

main().catch(console.error);

const http = require('http');
const fs = require('fs');

const options = {
  hostname: 'the-agent-company.com',
  port: 8929,
  path: '/api/v4/projects/root%2Fsotopia/repository/tree?per_page=100',
  method: 'GET',
  headers: {
    'PRIVATE-TOKEN': 'root'
  }
};

const req = http.request(options, (res) => {
  let data = '';
  res.on('data', (chunk) => { data += chunk; });
  res.on('end', () => {
    fs.writeFileSync('/tmp/repo_tree.json', data);
    console.log('Done. Status:', res.statusCode);
    console.log('Data:', data);
  });
});

req.on('error', (e) => { console.error('Error:', e.message); });
req.end();
